package edu.rice.comp322;

import java.awt.Dimension;
import java.awt.GridBagConstraints;
import java.awt.GridBagLayout;
import java.awt.Insets;
import java.util.ArrayList;
import java.util.List;
import java.util.prefs.Preferences;
import javax.swing.*;
import javax.swing.table.DefaultTableModel;

import static edu.rice.hj.Module0.launchHabaneroApp;

/**
 * User-Interface for loading the contributors for all repositories
 * under the given organization.
 */
public class ContributorsUI extends JFrame implements LoadContributors {

    private final JTextField username = new JTextField(20);
    private final JPasswordField password = new JPasswordField(20);
    private final JTextField org = new JTextField(20);
    private final JButton load = new JButton("Load contributors");
    private final Insets insets = new Insets(3, 10, 3, 10);
    private final String[] columns = {"Login", "Contributions"};
    private final DefaultTableModel resultsModel = new DefaultTableModel(columns, 0);
    public List<User> users = new ArrayList<>();
    private final JTable results = new JTable(resultsModel);
    private final JScrollPane resultsScroll = new JScrollPane(results);
    private Preferences pref;

    public ContributorsUI() {
        init();
    }

    /**
     * Updates the contributors list displayed on the user-interface.
     * @param users a list of Users
     */
    public void updateContributors(List<User> users) {
        Object[][] values = new Object[users.size()][2];
        for (int i = 0; i < users.size(); i++) {
            values[i] = new Object[]{users.get(i).login, users.get(i).contributions};
        }
        this.users = users;
        resultsModel.setDataVector(values, columns);
    }

    /**
     * Adds action listener for load button.
     */
    private void addLoadListener() {
        load.addActionListener(e -> {
            String userParam = username.getText();
            String passParam = String.valueOf(password.getPassword());
            String orgParam = org.getText();
            if (!userParam.isEmpty() && !passParam.isEmpty()) {
                saveParams(userParam, passParam, orgParam);
            }
            new Thread(()-> {
                launchHabaneroApp(() -> {
                    try {
                        System.out.println("Loading Users ...");
                        loadContributorsPar(userParam, passParam, orgParam);
                    } catch (Exception exception) {
                        exception.printStackTrace();
                    }
                });
            }).start();
        });
    }

    /**
     * Sets the parameters.
     */
    public void setParams(String userParam, String passParam, String orgParam) {
        username.setText(userParam);
        password.setText(passParam);
        org.setText(orgParam);
    }

    /**
     * Saves the parameter data.
     */
    public void saveParams(String userParam, String passParam, String orgParam) {
        this.pref.put("username", userParam);
        this.pref.put("password", passParam);
        this.pref.put("org", orgParam);
    }

    /**
     * Initializes the user interface.
     */
    private void init() {
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setBounds(100, 100, 500, 350);
        resultsScroll.setPreferredSize(new Dimension(200, 200));
        JPanel contentPane = new JPanel(new GridBagLayout());
        setContentPane(contentPane);
        addLabeled("GitHub Username", username);
        addLabeled("Password/Token", password);
        addWideSeparator();
        addLabeled("Organization", org);
        addWideSeparator();
        addLoad();
        addResultsScroll();
        this.pref = Preferences.userRoot().node("edu.rice.comp322.ContributorsUI");
        setParams(pref.get("username", ""), pref.get("password", ""), pref.get("org", ""));
        addLoadListener();
        updateContributors(new ArrayList<>());
    }


    /**
     * Adds labeled components.
     */
    private void addLabeled(String label, JComponent component) {
        GridBagConstraints constraintslbl =  new GridBagConstraints();
        constraintslbl.gridx = 0;
        constraintslbl.insets = insets;
        add(new JLabel(label), constraintslbl);
        GridBagConstraints constraintsComponent = new GridBagConstraints();
        constraintsComponent.gridx = 1;
        constraintsComponent.insets = insets;
        constraintsComponent.anchor = GridBagConstraints.WEST;
        constraintsComponent.fill = GridBagConstraints.HORIZONTAL;
        constraintsComponent.weightx = 1.0;
        add(component, constraintsComponent);
    }

    /**
     * Adds separator.
     */
    private void addWideSeparator() {
        GridBagConstraints constraints = new GridBagConstraints();
        constraints.gridx = 0;
        constraints.gridwidth = 2;
        constraints.insets = insets;
        constraints.fill = GridBagConstraints.HORIZONTAL;
        add(new JSeparator(), constraints);
    }

    /**
     * Adds load button.
     */
    private void addLoad() {
        GridBagConstraints constraints = new GridBagConstraints();
        constraints.gridx = 0;
        constraints.gridwidth = 2;
        constraints.insets = insets;
        add(load, constraints);
    }

    /**
     * Add scrollbar for results.
     */
    private void addResultsScroll() {
        GridBagConstraints constraints = new GridBagConstraints();
        constraints.gridx = 0;
        constraints.gridwidth = 2;
        constraints.insets = insets;
        constraints.weightx = 1.0;
        constraints.weighty = 1.0;
        constraints.fill = GridBagConstraints.BOTH;
        add(resultsScroll, constraints);
    }

    public void start() {
        this.setVisible(true);
    }

}

package edu.rice.comp322;

import okhttp3.OkHttpClient;
import okhttp3.Request;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;
import edu.rice.hj.api.HjFuture;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

import static edu.rice.hj.Module1.future;
import static java.nio.charset.StandardCharsets.UTF_8;

/**
 * Loads the contributors using the GitHub service.
 */
public interface LoadContributors {

    /**
     * Performs requests to GitHub and loads and aggregates the contributors for all
     * repositories under the given organization.
     */
    default int loadContributorsSeq(String username, String password, String org)
        throws IOException {

        //Create the service to make the requests
        GitHubService service = createGitHubService(username, password);

        //Get all the repos under the given organization
        List<Repo> repos = service.getOrgReposCall(org).execute().body();
        if (repos == null) {
            System.err.println("Error making request to GitHub. Make sure token and organization name are correct.");
            return 0;
        } else if (repos.size() == 0) {
            System.out.println("0 repositories found in " + org + " organization, make sure your token is correct.");
        } else {
            System.out.println("Found " + repos.size() + " repositories in " + org + " organization.");
        }

        //Get the contributors for each repo
        List<User> users = new ArrayList<>();
        for (Repo repo : repos) {
            List<User> tempUsers = service.getRepContributorsCall(org, repo.name).execute().body();
            if (tempUsers != null) {
                users.addAll(tempUsers);
                System.out.println("Found " + tempUsers.size() + " users in " + repo.name + " repository.");
            } else {
                System.err.println("Error making request to GitHub for repository " + repo.name);
            }
        }

        //Aggregate the number of contributions for each user
        System.out.println("Aggregating Results");
        List<User> aggregatedUsers = new ArrayList<>();
        for (User user: users) {
            if (aggregatedUsers.contains(user)) {
                aggregatedUsers.get(aggregatedUsers.indexOf(user)).contributions += user.contributions;
            } else {
                aggregatedUsers.add(user);
            }
        }

        //Sort the users in descending order of contributions
        aggregatedUsers.sort((o1, o2) -> o2.contributions - o1.contributions);
        System.out.println("Displaying Results");
        updateContributors(aggregatedUsers);
        return repos.size();
    }

    /**
     * Performs requests to GitHub and loads and aggregates the contributors for all
     * repositories under the given organization in parallel using futures.
     * <p>
     * Implementation uses HJlib futures to fetch contributors for each repository
     * concurrently, then aggregates results using streams.
     * </p>
     * <p>
     * Requirements (from assignment):
     * Use futures, data-driven tasks, and streams (not finish or async).
     * UI must not freeze when loading data.
     * Work metric should be bounded by O(repos).
     * Must produce same results as loadContributorsSeq.
     * </p>
     */
    default int loadContributorsPar(String username, String password, String org)
        throws IOException {

        // Create the service to make the requests
        GitHubService service = createGitHubService(username, password);

        // Get all the repos under the given organization (sequential - one API call)
        List<Repo> repos = service.getOrgReposCall(org).execute().body();
        if (repos == null) {
            System.err.println("Error making request to GitHub. Make sure token and organization name are correct.");
            return 0;
        } else if (repos.size() == 0) {
            System.out.println("0 repositories found in " + org + " organization, make sure your token is correct.");
            updateContributors(new ArrayList<>());
            return 0;
        } else {
            System.out.println("Found " + repos.size() + " repositories in " + org + " organization.");
        }

        final int N = repos.size();

        // Create one future per repo to fetch contributors concurrently.
        @SuppressWarnings("unchecked")
        final HjFuture<List<User>>[] repoFutures = new HjFuture[N];
        for (int i = 0; i < N; i++) {
            final String repoName = repos.get(i).name;
            repoFutures[i] = future(() -> {
                try {
                    List<User> users = service.getRepContributorsCall(org, repoName).execute().body();
                    if (users != null) {
                        System.out.println("Found " + users.size() + " users in " + repoName + " repository.");
                        return users;
                    } else {
                        System.err.println("Error making request to GitHub for repository " + repoName);
                        return new ArrayList<>();
                    }
                } catch (IOException e) {
                    System.err.println("IOException for repository " + repoName + ": " + e.getMessage());
                    return new ArrayList<>();
                }
            });
        }

        // Aggregate future (data-driven task): collects results from all repo futures,
        // aggregates contributions, and updates the UI.
        // f.get() inside a future body is legal — SuspendableException propagates
        // through HjSuspendingCallable, allowing HJlib to suspend/resume correctly.
        // The surrounding launchHabaneroApp finish barrier ensures this task completes
        // before the test verifier runs.
        future(() -> {
            System.out.println("Aggregating Results");
            List<User> allUsers = new ArrayList<>();
            for (HjFuture<List<User>> f : repoFutures) {
                List<User> users = f.get();
                if (users != null) {
                    allUsers.addAll(users);
                }
            }

            // Stream-based aggregation: sum contributions per unique login
            List<User> aggregatedUsers = allUsers.stream()
                .collect(Collectors.groupingBy(
                    u -> u.login,
                    Collectors.summingInt(u -> u.contributions)
                ))
                .entrySet().stream()
                .map(entry -> new User(entry.getKey(), entry.getValue()))
                .sorted((o1, o2) -> o2.contributions - o1.contributions)
                .collect(Collectors.toList());

            System.out.println("Displaying Results");
            updateContributors(aggregatedUsers);
            return null;
        });

        // Return immediately — the launchHabaneroApp finish barrier ensures
        // the aggregate future completes before the caller proceeds.
        return N;
    }

    /**
     * Creates the GitHub service with correct authorization.
     * <p>
     * If the system property "MOCK_GITHUB" is set to "true", uses pre-recorded
     * mock responses instead of making real API calls. This enables testing
     * without GitHub credentials.
     * </p>
     */
    default GitHubService createGitHubService(String username, String password) {
        String authToken = "Basic " + new String(Base64.getEncoder().encode((username + ":" + password).getBytes()), UTF_8);

        OkHttpClient.Builder clientBuilder = new OkHttpClient.Builder();

        // Check for mock mode (set via -DMOCK_GITHUB=true or environment variable)
        String mockMode = System.getProperty("MOCK_GITHUB", System.getenv("MOCK_GITHUB"));
        if ("true".equalsIgnoreCase(mockMode)) {
            clientBuilder.addInterceptor(new MockGitHubInterceptor());
            System.out.println("[MockMode] Using pre-recorded GitHub API responses");
        }

        // Add auth header interceptor (still needed for request structure, even if mocked)
        clientBuilder.addInterceptor(chain -> {
            Request original = chain.request();
            Request.Builder builder = original.newBuilder()
                .header("Accept", "application/vnd.github.v3+json")
                .header("Authorization", authToken);
            Request request = builder.build();
            return chain.proceed(request);
        });

        OkHttpClient httpClient = clientBuilder.build();
        Retrofit retrofit = new Retrofit.Builder()
            .baseUrl("https://api.github.com")
            .addConverterFactory(GsonConverterFactory.create())
            .client(httpClient)
            .build();
        return retrofit.create(GitHubService.class);
    }

    /**
     * Updates the contributors list displayed on the user-interface.
     * @param users a list of Users
     */
    void updateContributors(List<User> users);

}

